@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<script type="module" src="@Assets["Components/Pages/Notepad.razor.js"]"></script>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"
              @bind:after="OnContentChanged"></textarea>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private string? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>("import",
            "./" + Assets["Components/Pages/Notepad.razor.js"]);

        var restored = await module.InvokeAsync<string?>("load");
        if (restored is not null)
        {
            content = restored;
            savedContent = restored;
            StateHasChanged();
        }

        autoSaveTimer = new System.Threading.Timer(async _ =>
        {
            await InvokeAsync(async () =>
            {
                if (content != savedContent)
                {
                    await Save();
                    StateHasChanged();
                }
            });
        }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    private async Task Save()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", content);
        savedContent = content;
        lastSavedAt = DateTime.Now.ToString("HH:mm:ss");
        await module.InvokeVoidAsync("setBeforeUnload", false);
    }

    private async Task SaveNow() => await Save();

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("clear");
            await module.InvokeVoidAsync("setBeforeUnload", false);
        }
    }

    private async Task OnContentChanged()
    {
        if (module is not null && content != savedContent)
        {
            await module.InvokeVoidAsync("setBeforeUnload", true);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("setBeforeUnload", false);
            }
            catch (JSDisconnectedException) { }
            await module.DisposeAsync();
        }
    }
}

